def get_group_by_cols(self, alias=None):
    # If this expression is referenced by an alias for an explicit GROUP BY
    # through values() a reference to this expression and not the
    # underlying .query must be returned to ensure external column
    # references are not grouped against as well.
    if alias:
        return [Ref(alias, self)]
    return self.query.get_group_by_cols()

def as_sql(self, with_limits=True, with_col_aliases=False):
    """
    Create the SQL for this query. Return the SQL string and list of
    parameters.

    If 'with_limits' is False, any limit/offset information is not included
    in the query.
    """
    refcounts_before = self.query.alias_refcount.copy()
    try:
        extra_select, order_by, group_by = self.pre_sql_setup()
        for_update_part = None
        # Is a LIMIT/OFFSET clause needed?
        with_limit_offset = with_limits and (self.query.high_mark is not None or self.query.low_mark)
        combinator = self.query.combinator
        features = self.connection.features
        if combinator:
            if not getattr(features, 'supports_select_{}'.format(combinator)):
                raise NotSupportedError('{} is not supported on this database backend.'.format(combinator))
            result, params = self.get_combinator_sql(combinator, self.query.combinator_all)
        else:
            distinct_fields, distinct_params = self.get_distinct()
            # This must come after 'select', 'ordering', and 'distinct'
            # (see docstring of get_from_clause() for details).
            from_, f_params = self.get_from_clause()
            try:
                where, w_params = self.compile(self.where) if self.where is not None else ('', [])
            except EmptyResultSet:
                if self.elide_empty:
                    raise
                # Use a predicate that's always False.
                where, w_params = '0 = 1', []
            having, h_params = self.compile(self.having) if self.having is not None else ("", [])
            result = ['SELECT']
            params = []

            if self.query.distinct:
                distinct_result, distinct_params = self.connection.ops.distinct_sql(
                    distinct_fields,
                    distinct_params,
                )
                result += distinct_result
                params += distinct_params

            out_cols = []
            col_idx = 1
            for _, (s_sql, s_params), alias in self.select + extra_select:
                if alias:
                    s_sql = '%s AS %s' % (s_sql, self.connection.ops.quote_name(alias))
                elif with_col_aliases:
                    s_sql = '%s AS %s' % (
                        s_sql,
                        self.connection.ops.quote_name('col%d' % col_idx),
                    )
                    col_idx += 1
                params.extend(s_params)
                out_cols.append(s_sql)

            result += [', '.join(out_cols), 'FROM', *from_]
            params.extend(f_params)

            if self.query.select_for_update and self.connection.features.has_select_for_update:
                if self.connection.get_autocommit():
                    raise TransactionManagementError('select_for_update cannot be used outside of a transaction.')

                if with_limit_offset and not self.connection.features.supports_select_for_update_with_limit:
                    raise NotSupportedError(
                        'LIMIT/OFFSET is not supported with '
                        'select_for_update on this database backend.'
                    )
                nowait = self.query.select_for_update_nowait
                skip_locked = self.query.select_for_update_skip_locked
                of = self.query.select_for_update_of
                no_key = self.query.select_for_no_key_update
                # If it's a NOWAIT/SKIP LOCKED/OF/NO KEY query but the
                # backend doesn't support it, raise NotSupportedError to
                # prevent a possible deadlock.
                if nowait and not self.connection.features.has_select_for_update_nowait:
                    raise NotSupportedError('NOWAIT is not supported on this database backend.')
                elif skip_locked and not self.connection.features.has_select_for_update_skip_locked:
                    raise NotSupportedError('SKIP LOCKED is not supported on this database backend.')
                elif of and not self.connection.features.has_select_for_update_of:
                    raise NotSupportedError('FOR UPDATE OF is not supported on this database backend.')
                elif no_key and not self.connection.features.has_select_for_no_key_update:
                    raise NotSupportedError(
                        'FOR NO KEY UPDATE is not supported on this '
                        'database backend.'
                    )
                for_update_part = self.connection.ops.for_update_sql(
                    nowait=nowait,
                    skip_locked=skip_locked,
                    of=self.get_select_for_update_of_arguments(),
                    no_key=no_key,
                )

            if for_update_part and self.connection.features.for_update_after_from:
                result.append(for_update_part)

            if where:
                result.append('WHERE %s' % where)
                params.extend(w_params)

            grouping = []
            for g_sql, g_params in group_by:
                grouping.append(g_sql)
                params.extend(g_params)
            if grouping:
                if distinct_fields:
                    raise NotImplementedError('annotate() + distinct(fields) is not implemented.')
                order_by = order_by or self.connection.ops.force_no_ordering()
                result.append('GROUP BY %s' % ', '.join(grouping))
                if self._meta_ordering:
                    order_by = None
            if having:
                result.append('HAVING %s' % having)
                params.extend(h_params)

        if self.query.explain_info:
            result.insert(0, self.connection.ops.explain_query_prefix(
                self.query.explain_info.format,
                **self.query.explain_info.options
            ))

        if order_by:
            ordering = []
            for _, (o_sql, o_params, _) in order_by:
                ordering.append(o_sql)
                params.extend(o_params)
            result.append('ORDER BY %s' % ', '.join(ordering))

        if with_limit_offset:
            result.append(self.connection.ops.limit_offset_sql(self.query.low_mark, self.query.high_mark))

        if for_update_part and not self.connection.features.for_update_after_from:
            result.append(for_update_part)

        if self.query.subquery and extra_select:
            # If the query is used as a subquery, the extra selects would
            # result in more columns than the left-hand side expression is
            # expecting. This can happen when a subquery uses a combination
            # of order_by() and distinct(), forcing the ordering expressions
            # to be selected as well. Wrap the query in another subquery
            # to exclude extraneous selects.
            sub_selects = []
            sub_params = []
            for index, (select, _, alias) in enumerate(self.select, start=1):
                if not alias and with_col_aliases:
                    alias = 'col%d' % index
                if alias:
                    sub_selects.append("%s.%s" % (
                        self.connection.ops.quote_name('subquery'),
                        self.connection.ops.quote_name(alias),
                    ))
                else:
                    select_clone = select.relabeled_clone({select.alias: 'subquery'})
                    subselect, subparams = select_clone.as_sql(self, self.connection)
                    sub_selects.append(subselect)
                    sub_params.extend(subparams)
            return 'SELECT %s FROM (%s) subquery' % (
                ', '.join(sub_selects),
                ' '.join(result),
            ), tuple(sub_params + params)

        return ' '.join(result), tuple(params)
    finally:
        # Finally do cleanup - get rid of the joins we created above.
        self.query.reset_refcounts(refcounts_before)

def get_combinator_sql(self, combinator, all):
    features = self.connection.features
    compilers = [
        query.get_compiler(self.using, self.connection, self.elide_empty)
        for query in self.query.combined_queries if not query.is_empty()
    ]
    if not features.supports_slicing_ordering_in_compound:
        for query, compiler in zip(self.query.combined_queries, compilers):
            if query.low_mark or query.high_mark:
                raise DatabaseError('LIMIT/OFFSET not allowed in subqueries of compound statements.')
            if compiler.get_order_by():
                raise DatabaseError('ORDER BY not allowed in subqueries of compound statements.')
    parts = ()
    for compiler in compilers:
        try:
            # If the columns list is limited, then all combined queries
            # must have the same columns list. Set the selects defined on
            # the query on all combined queries, if not already set.
            if not compiler.query.values_select and self.query.values_select:
                compiler.query = compiler.query.clone()
                compiler.query.set_values((
                    *self.query.extra_select,
                    *self.query.values_select,
                    *self.query.annotation_select,
                ))
            part_sql, part_args = compiler.as_sql()
            if compiler.query.combinator:
                # Wrap in a subquery if wrapping in parentheses isn't
                # supported.
                if not features.supports_parentheses_in_compound:
                    part_sql = 'SELECT * FROM ({})'.format(part_sql)
                # Add parentheses when combining with compound query if not
                # already added for all compound queries.
                elif not features.supports_slicing_ordering_in_compound:
                    part_sql = '({})'.format(part_sql)
            parts += ((part_sql, part_args),)
        except EmptyResultSet:
            # Omit the empty queryset with UNION and with DIFFERENCE if the
            # first queryset is nonempty.
            if combinator == 'union' or (combinator == 'difference' and parts):
                continue
            raise
    if not parts:
        raise EmptyResultSet
    combinator_sql = self.connection.ops.set_operators[combinator]
    if all and combinator == 'union':
        combinator_sql += ' ALL'
    braces = '({})' if features.supports_slicing_ordering_in_compound else '{}'
    sql_parts, args_parts = zip(*((braces.format(sql), args) for sql, args in parts))
    result = [' {} '.format(combinator_sql).join(sql_parts)]
    params = []
    for part in args_parts:
        params.extend(part)
    return result, params

def _reordered_actions(self, actions):
    return sorted(
        actions, key=lambda a: set(a.option_strings) & self.show_last != set()
    )

def add_base_argument(self, parser, *args, **kwargs):
    """
    Call the parser's add_argument() method, suppressing the help text
    according to BaseCommand.suppressed_base_arguments.
    """
    for arg in args:
        if arg in self.suppressed_base_arguments:
            kwargs["help"] = argparse.SUPPRESS
            break
    parser.add_argument(*args, **kwargs)

def parse_args(self, args=None, namespace=None):
    # Catch missing argument for a better error message
    if self.missing_args_message and not (
        args or any(not arg.startswith("-") for arg in args)
    ):
        self.error(self.missing_args_message)
    return super().parse_args(args, namespace)

def error(self, message):
    if self.called_from_command_line:
        super().error(message)
    else:
        raise CommandError("Error: %s" % message)

def get_urls(self):
    from django.urls import path

    def wrap(view):
        def wrapper(*args, **kwargs):
            return self.admin_site.admin_view(view)(*args, **kwargs)

        wrapper.model_admin = self
        return update_wrapper(wrapper, view)

    info = self.opts.app_label, self.opts.model_name

    return [
        path("", wrap(self.changelist_view), name="%s_%s_changelist" % info),
        path("add/", wrap(self.add_view), name="%s_%s_add" % info),
        path(
            "<path:object_id>/history/",
            wrap(self.history_view),
            name="%s_%s_history" % info,
        ),
        path(
            "<path:object_id>/delete/",
            wrap(self.delete_view),
            name="%s_%s_delete" % info,
        ),
        path(
            "<path:object_id>/change/",
            wrap(self.change_view),
            name="%s_%s_change" % info,
        ),
        # For backwards compatibility (was the change url before 1.9)
        path(
            "<path:object_id>/",
            wrap(
                RedirectView.as_view(
                    pattern_name="%s:%s_%s_change"
                    % ((self.admin_site.name,) + info)
                )
            ),
        ),
    ]

def get_object(self, request, object_id, from_field=None):
    """
    Return an instance matching the field and value provided, the primary
    key is used if no field is provided. Return ``None`` if no match is
    found or the object_id fails validation.
    """
    queryset = self.get_queryset(request)
    model = queryset.model
    field = (
        model._meta.pk if from_field is None else model._meta.get_field(from_field)
    )
    try:
        object_id = field.to_python(object_id)
        return queryset.get(**{field.name: object_id})
    except (model.DoesNotExist, ValidationError, ValueError):
        return None

def get_changelist_form(self, request, **kwargs):
    """
    Return a Form class for use in the Formset on the changelist page.
    """
    defaults = {
        "formfield_callback": partial(self.formfield_for_dbfield, request=request),
        **kwargs,
    }
    if defaults.get("fields") is None and not modelform_defines_fields(
        defaults.get("form")
    ):
        defaults["fields"] = forms.ALL_FIELDS

    return modelform_factory(self.model, **defaults)

def get_changelist_formset(self, request, **kwargs):
    """
    Return a FormSet class for use on the changelist page if list_editable
    is used.
    """
    defaults = {
        "formfield_callback": partial(self.formfield_for_dbfield, request=request),
        **kwargs,
    }
    return modelformset_factory(
        self.model,
        self.get_changelist_form(request),
        extra=0,
        fields=self.list_editable,
        **defaults,
    )

def get_formsets_with_inlines(self, request, obj=None):
    """
    Yield formsets and the corresponding inlines.
    """
    for inline in self.get_inline_instances(request, obj):
        yield inline.get_formset(request, obj), inline

def __init__(self, *args, **kwargs):
    super().__init__(*args, **kwargs)
    password = self.fields.get("password")
    if password:
        password.help_text = password.help_text.format("../password/")
    user_permissions = self.fields.get("user_permissions")
    if user_permissions:
        user_permissions.queryset = user_permissions.queryset.select_related(
            "content_type"
        )

def new_figure_manager_given_figure(cls, num, figure):
    """Create a new figure manager instance for the given figure."""
    return cls.FigureCanvas.new_manager(figure, num)

def standardize(self, val: ColorSpec) -> RGBTuple | RGBATuple:
    # Return color with alpha channel only if the input spec has it
    # This is so that RGBA colors can override the Alpha property
    if to_rgba(val) != to_rgba(val, 1):
        return to_rgba(val)
    else:
        return to_rgb(val)

def infer_scale(self, arg: Any, data: Series) -> Scale:
    # TODO when inferring Continuous without data, verify type

    # TODO need to rethink the variable type system
    # (e.g. boolean, ordered categories as Ordinal, etc)..
    var_type = variable_type(data, boolean_type="categorical")

    if isinstance(arg, (dict, list)):
        return Nominal(arg)

    if isinstance(arg, tuple):
        if var_type == "categorical":
            # TODO It seems reasonable to allow a gradient mapping for nominal
            # scale but it also feels "technically" wrong. Should this infer
            # Ordinal with categorical data and, if so, verify orderedness?
            return Nominal(arg)
        return Continuous(arg)

    if callable(arg):
        return Continuous(arg)

    # TODO Do we accept str like "log", "pow", etc. for semantics?

    # TODO what about
    # - Temporal? (i.e. datetime)
    # - Boolean?

    if not isinstance(arg, str):
        msg = " ".join([
            f"A single scale argument for {self.variable} variables must be",
            f"a string, dict, tuple, list, or callable, not {type(arg)}."
        ])
        raise TypeError(msg)

    if arg in QUAL_PALETTES:
        return Nominal(arg)
    elif var_type == "numeric":
        return Continuous(arg)
    # TODO implement scales for date variables and any others.
    else:
        return Nominal(arg)

def _get_transform(self):

    arg = self.trans

    def get_param(method, default):
        if arg == method:
            return default
        return float(arg[len(method):])

    if arg is None:
        return _make_identity_transforms()
    elif isinstance(arg, tuple):
        return arg
    elif isinstance(arg, str):
        if arg == "ln":
            return _make_log_transforms()
        elif arg == "logit":
            base = get_param("logit", 10)
            return _make_logit_transforms(base)
        elif arg.startswith("log"):
            base = get_param("log", 10)
            return _make_log_transforms(base)
        elif arg.startswith("symlog"):
            c = get_param("symlog", 1)
            return _make_symlog_transforms(c)
        elif arg.startswith("pow"):
            exp = get_param("pow", 2)
            return _make_power_transforms(exp)
        elif arg == "sqrt":
            return _make_sqrt_transforms()
        else:
            raise ValueError(f"Unknown value provided for trans: {arg!r}")

def _parse_for_log_params(
    self, trans: str | TransFuncs | None
) -> tuple[float | None, float | None]:

    log_base = symlog_thresh = None
    if isinstance(trans, str):
        m = re.match(r"^log(\d*)", trans)
        if m is not None:
            log_base = float(m[1] or 10)
        m = re.match(r"symlog(\d*)", trans)
        if m is not None:
            symlog_thresh = float(m[1] or 1)
    return log_base, symlog_thresh

def _get_locators(self, locator, at, upto, count, every, between, minor):

    log_base, symlog_thresh = self._parse_for_log_params(self.trans)

    if locator is not None:
        major_locator = locator

    elif upto is not None:
        if log_base:
            major_locator = LogLocator(base=log_base, numticks=upto)
        else:
            major_locator = MaxNLocator(upto, steps=[1, 1.5, 2, 2.5, 3, 5, 10])

    elif count is not None:
        if between is None:
            # This is rarely useful (unless you are setting limits)
            major_locator = LinearLocator(count)
        else:
            if log_base or symlog_thresh:
                forward, inverse = self._get_transform()
                lo, hi = forward(between)
                ticks = inverse(np.linspace(lo, hi, num=count))
            else:
                ticks = np.linspace(*between, num=count)
            major_locator = FixedLocator(ticks)

    elif every is not None:
        if between is None:
            major_locator = MultipleLocator(every)
        else:
            lo, hi = between
            ticks = np.arange(lo, hi + every, every)
            major_locator = FixedLocator(ticks)

    elif at is not None:
        major_locator = FixedLocator(at)

    else:
        if log_base:
            major_locator = LogLocator(log_base)
        elif symlog_thresh:
            major_locator = SymmetricalLogLocator(linthresh=symlog_thresh, base=10)
        else:
            major_locator = AutoLocator()

    if minor is None:
        minor_locator = LogLocator(log_base, subs=None) if log_base else None
    else:
        if log_base:
            subs = np.linspace(0, log_base, minor + 2)[1:-1]
            minor_locator = LogLocator(log_base, subs=subs)
        else:
            minor_locator = AutoMinorLocator(minor + 1)

    return major_locator, minor_locator

def _get_formatter(self, locator, formatter, like, base, unit):

    log_base, symlog_thresh = self._parse_for_log_params(self.trans)
    if base is default:
        if symlog_thresh:
            log_base = 10
        base = log_base

    if formatter is not None:
        return formatter

    if like is not None:
        if isinstance(like, str):
            if "{x" in like or "{pos" in like:
                fmt = like
            else:
                fmt = f"{{x:{like}}}"
            formatter = StrMethodFormatter(fmt)
        else:
            formatter = FuncFormatter(like)

    elif base is not None:
        # We could add other log options if necessary
        formatter = LogFormatterSciNotation(base)

    elif unit is not None:
        if isinstance(unit, tuple):
            sep, unit = unit
        elif not unit:
            sep = ""
        else:
            sep = " "
        formatter = EngFormatter(unit, sep=sep)

    else:
        formatter = ScalarFormatter()

    return formatter

def dataset_repr(ds):
    summary = ["<xarray.{}>".format(type(ds).__name__)]

    col_width = _calculate_col_width(_get_col_items(ds.variables))

    dims_start = pretty_print("Dimensions:", col_width)
    summary.append("{}({})".format(dims_start, dim_summary(ds)))

    if ds.coords:
        summary.append(coords_repr(ds.coords, col_width=col_width))

    unindexed_dims_str = unindexed_dims_repr(ds.dims, ds.coords)
    if unindexed_dims_str:
        summary.append(unindexed_dims_str)

    summary.append(data_vars_repr(ds.data_vars, col_width=col_width))

    if ds.attrs:
        summary.append(attrs_repr(ds.attrs))

    return "\n".join(summary)

def coords_repr(coords, col_width=None):
    if col_width is None:
        col_width = _calculate_col_width(_get_col_items(coords))
    return _mapping_repr(
        coords, title="Coordinates", summarizer=summarize_coord, col_width=col_width
    )

def summarize_coord(name: Hashable, var, col_width: int):
    is_index = name in var.dims
    marker = "*" if is_index else " "
    if is_index:
        coord = var.variable.to_index_variable()
        if coord.level_names is not None:
            return "\n".join(
                [
                    _summarize_coord_multiindex(coord, col_width, marker),
                    _summarize_coord_levels(coord, col_width),
                ]
            )
    return summarize_variable(name, var.variable, col_width, marker)

def summarize_variable(
    name: Hashable, var, col_width: int, marker: str = " ", max_width: int = None
):
    """Summarize a variable in one line, e.g., for the Dataset.__repr__."""
    if max_width is None:
        max_width_options = OPTIONS["display_width"]
        if not isinstance(max_width_options, int):
            raise TypeError(f"`max_width` value of `{max_width}` is not a valid int")
        else:
            max_width = max_width_options
    first_col = pretty_print(f"  {marker} {name} ", col_width)
    if var.dims:
        dims_str = "({}) ".format(", ".join(map(str, var.dims)))
    else:
        dims_str = ""
    front_str = f"{first_col}{dims_str}{var.dtype} "

    values_width = max_width - len(front_str)
    values_str = inline_variable_array_repr(var, values_width)

    return front_str + values_str

def inline_variable_array_repr(var, max_width):
    """Build a one-line summary of a variable's data."""
    if var._in_memory:
        return format_array_flat(var, max_width)
    elif isinstance(var._data, dask_array_type):
        return inline_dask_repr(var.data)
    elif isinstance(var._data, sparse_array_type):
        return inline_sparse_repr(var.data)
    elif hasattr(var._data, "__array_function__"):
        return maybe_truncate(repr(var._data).replace("\n", " "), max_width)
    else:
        # internal xarray array type
        return "..."

def dim_summary(obj):
    elements = [f"{k}: {v}" for k, v in obj.sizes.items()]
    return ", ".join(elements)

def coords(self) -> DatasetCoordinates:
    """Dictionary of xarray.DataArray objects corresponding to coordinate
    variables
    """
    return DatasetCoordinates(self)

def _get_ansi_code(msg_style: MessageStyle) -> str:
    """Return ANSI escape code corresponding to color and style.

    :param msg_style: the message style

    :raise KeyError: if a nonexistent color or style identifier is given

    :return: the built escape code
    """
    ansi_code = [ANSI_STYLES[effect] for effect in msg_style.style]
    if msg_style.color:
        if msg_style.color.isdigit():
            ansi_code.extend(["38", "5"])
            ansi_code.append(msg_style.color)
        else:
            ansi_code.append(ANSI_COLORS[msg_style.color])
    if ansi_code:
        return ANSI_PREFIX + ";".join(ansi_code) + ANSI_END
    return ""

